using System.Threading.Channels;

/// <summary>
/// Modern .NET 8 event processor using Channel&lt;T&gt; for backpressure-aware,
/// signal-safe producer/consumer semantics. Replaces ManualResetEvent + Queue
/// + Thread.Abort/Interrupt with structured concurrency.
/// </summary>
public sealed class EventProcessor : IAsyncDisposable, IDisposable
{
    private readonly Channel<string> _channel;
    private readonly CancellationTokenSource _cts = new();
    private Task? _workerTask;

    public EventProcessor(int capacity = 1000)
    {
        // BoundedChannel gives backpressure; use UnboundedChannel if you
        // prefer the original unbounded Queue behavior.
        _channel = Channel.CreateBounded<string>(new BoundedChannelOptions(capacity)
        {
            FullMode = BoundedChannelFullMode.Wait,
            SingleReader = true,   // one consumer  → enables lock-free fast path
            SingleWriter = false,  // multiple producers allowed
        });
    }

    public void Start()
    {
        _workerTask = Task.Run(() => RunLoopAsync(_cts.Token));
    }

    private async Task RunLoopAsync(CancellationToken ct)
    {
        try
        {
            // ReadAllAsync yields items as they arrive and completes
            // when the channel is marked complete AND drained.
            await foreach (var item in _channel.Reader.ReadAllAsync(ct))
            {
                Handle(item);
            }
        }
        catch (OperationCanceledException) when (ct.IsCancellationRequested)
        {
            // Graceful shutdown — expected, not an error.
        }
    }

    public async ValueTask EnqueueAsync(string item, CancellationToken ct = default)
    {
        await _channel.Writer.WriteAsync(item, ct);
    }

    // Synchronous convenience overload (mirrors original API surface).
    public void Enqueue(string item)
    {
        // TryWrite succeeds immediately when channel has capacity.
        if (!_channel.Writer.TryWrite(item))
        {
            // Channel full — block the caller (matches original behavior).
            _channel.Writer.WriteAsync(item).AsTask().GetAwaiter().GetResult();
        }
    }

    public async Task StopAsync(TimeSpan? timeout = null)
    {
        // 1. Signal the channel as complete — no more writes accepted.
        _channel.Writer.TryComplete();

        // 2. Cancel the token to unblock ReadAllAsync if channel is empty.
        await _cts.CancelAsync();

        // 3. Wait for the worker to finish (with timeout).
        if (_workerTask is not null)
        {
            var effectiveTimeout = timeout ?? TimeSpan.FromSeconds(5);
            using var timeoutCts = new CancellationTokenSource(effectiveTimeout);
            try
            {
                await _workerTask.WaitAsync(timeoutCts.Token);
            }
            catch (TimeoutException)
            {
                // Worker didn't finish in time. In .NET 8 there is no
                // Thread.Abort — you must design Handle() to be
                // cancellation-aware. Log and move on.
                Console.Error.WriteLine(
                    "EventProcessor: worker did not stop within timeout.");
            }
        }
    }

    // Synchronous Stop (matches original API).
    public void Stop()
    {
        StopAsync(TimeSpan.FromSeconds(5)).GetAwaiter().GetResult();
    }

    private void Handle(string item)
    {
        // Your processing logic here.
        Console.WriteLine($"Handled: {item}");
    }

    public async ValueTask DisposeAsync()
    {
        await StopAsync();
        _cts.Dispose();
    }

    public void Dispose()
    {
        Stop();
        _cts.Dispose();
    }
}

